mapper.select:
select userId, userNick
from tb_user
where userId = #{userId} and userPw = #{userPw}

mapper.update:
update tb_user
set userPw = #{userPw}, userNick=#{userNick}, userRegion = #{userRegion}, userWeight = #{userWeight}, userHeight = #{userHeight},
userProfileImg = #{userProfileImg}, userProfileInfo = #{userProfileInfo} 
where userId = #{userId}

mapper.select:
select postContent, userNick from tb_post
inner join tb_user on tb_post.userId = tb_user.userId
order by postIdx desc;

SELECT COUNT(likeIdx) as cnt
FROM tb_like
WHERE postIdx=#{postIdx} AND userNick=#{userNick}

mapper.update:
UPDATE tb_like
SET likeCheck = likeCheck + 1 
WHERE userNick=#{userNick} AND postIdx=#{postIdx}

UPDATE tb_like
SET likeCheck = 0
WHERE userNick=#{userNick} AND postIdx=#{postIdx}

mapper.select:
SELECT likeIdx, postIdx, userNick, likeCheck 
FROM tb_like
WHERE postIdx=#{postIdx} AND userNick=#{userNick}

select userNick
from tb_user
